    17	export function injectPendingContext(
    18	  collector: ContextCollector,
    19	  sessionID: string,
    20	  parts: OutputPart[]
    21	): InjectionResult {
    22	  if (!collector.hasPending(sessionID)) {
    23	    return { injected: false, contextLength: 0 }
    24	  }
    25	
    26	  const textPartIndex = parts.findIndex((p) => p.type === "text" && p.text !== undefined)
    27	  if (textPartIndex === -1) {
    28	    return { injected: false, contextLength: 0 }
    29	  }
    30	
    31	  const pending = collector.consume(sessionID)
    32	  const originalText = parts[textPartIndex].text ?? ""
    33	  parts[textPartIndex].text = `${pending.merged}\n\n---\n\n${originalText}`
    34	
    35	  return {
    36	    injected: true,
    37	    contextLength: pending.merged.length,
    38	  }
    39	}
