import { describe, expect, it } from "bun:test"
import type { ToolContext } from "@opencode-ai/plugin/tool"
import { createSkillTool } from "./tools"
import type { LoadedSkill } from "../../features/opencode-skill-loader/types"

function createMockSkill(name: string, scope: string = "opencode-project"): LoadedSkill {
  return {
    name,
    path: `/test/skills/${name}/SKILL.md`,
    resolvedPath: `/test/skills/${name}`,
    definition: {
      name,
      description: `Test skill ${name}`,
      template: "Test template",
    },
    scope: scope as LoadedSkill["scope"],
  }
}

const mockContext: ToolContext = {
  sessionID: "test-session",
  messageID: "msg-1",
  agent: "test-agent",
  directory: "/test",
  worktree: "/test",
  abort: new AbortController().signal,
  metadata: () => {},
  ask: async () => {},
}

describe("skill tool - short name resolution", () => {
  it("should resolve skill by short name (last segment after /)", async () => {
    // given: a skill with a namespaced name like superpowers/systematic-debugging
    const loadedSkills = [
      createMockSkill("superpowers/systematic-debugging"),
    ]
    const tool = createSkillTool({ skills: loadedSkills })

    // when: invoking by short name
    const result = await tool.execute({ name: "systematic-debugging" }, mockContext)

    // then: should resolve to the full skill
    expect(result).toContain("Skill: superpowers/systematic-debugging")
  })

  it("should still resolve by full name", async () => {
    // given: a skill with a namespaced name
    const loadedSkills = [
      createMockSkill("superpowers/systematic-debugging"),
    ]
    const tool = createSkillTool({ skills: loadedSkills })

    // when: invoking by full name
    const result = await tool.execute({ name: "superpowers/systematic-debugging" }, mockContext)

    // then: should resolve correctly
    expect(result).toContain("Skill: superpowers/systematic-debugging")
  })

  it("should resolve skill by short name with leading slash", async () => {
    // given: a skill with a namespaced name
    const loadedSkills = [
      createMockSkill("superpowers/systematic-debugging"),
    ]
    const tool = createSkillTool({ skills: loadedSkills })

    // when: invoking by short name with leading slash
    const result = await tool.execute({ name: "/systematic-debugging" }, mockContext)

    // then: should resolve to the full skill
    expect(result).toContain("Skill: superpowers/systematic-debugging")
  })

